import React, { useState } from "react";
import { NOME_APP, CSS } from "./utils/constants";
import { LS, san } from "./utils/helpers";

// IMPORTANTE: Cole abaixo os componentes (Fld, Btn, Home, PedidoInfo, etc)
// Para que o App consiga enxergá-los.

export default function App() {
  const [screen, setScreen] = useState("home");
  const [cart, setCart] = useState([]);
  const [orders, setOrders] = useState([]);
  const [pedInfo, setPedInfo] = useState({ entrega:"", hora:"", obs:"", regiao:null, enderecoEntrega:"" });

  return (
    <div className="App">
       <style>{CSS}</style>

       {screen === "home" && (
         <Home 
           NOME_APP={NOME_APP}
           cart={cart}
           setScreen={setScreen}
           onPedido={() => setScreen("pedido-info")}
           onLogin={() => setScreen("client-login")}
         />
       )}

       {screen === "pedido-info" && (
         <PedidoInfo 
            pedInfo={pedInfo}
            setPedInfo={setPedInfo}
            onBack={() => setScreen("home")}
         />
       )}
    </div>
  );
}

